class CircuitBreaker {
  private failures = 0;
  private open = false;

  async call<T>(fn: () => Promise<T>): Promise<T> {
    if (this.open) throw new Error("Circuit open — fail fast");
    try {
      const result = await fn();
      this.failures = 0;
      return result;
    } catch (err) {
      this.failures++;
      if (this.failures >= 5) this.open = true;
      throw err;
    }
  }
}
